const now = Date.now();
const DAY = 1000 * 60 * 60 * 24;

const repoInfo = $('GitHub - Repo Info').item.json;
const prs = $('GitHub - Open PRs').item.json || [];
const allIssues = $('GitHub - Open Issues').item.json || [];
const ciData = $('GitHub - CI Runs').item.json || {};
const commits = $('GitHub - Recent Commits').item.json || [];

const issues = Array.isArray(allIssues) ? allIssues.filter(i => !i.pull_request) : [];
const prList = Array.isArray(prs) ? prs : [];
const ciRuns = ciData.workflow_runs || [];
const commitList = Array.isArray(commits) ? commits : [];

// ── PR health ─────────────────────────────────────────────────────
const stalePRs   = prList.filter(pr => (now - new Date(pr.created_at)) > 7  * DAY);
const ancientPRs = prList.filter(pr => (now - new Date(pr.created_at)) > 30 * DAY);
const avgPRAgeDays = prList.length > 0
  ? Math.round(prList.reduce((s, pr) => s + (now - new Date(pr.created_at)) / DAY, 0) / prList.length)
  : 0;

// ── Issue health ──────────────────────────────────────────────────
const staleIssues = issues.filter(i => (now - new Date(i.updated_at)) > 14 * DAY);
const unansweredIssues = issues.filter(i => i.comments === 0);
const avgIssueAgeDays = issues.length > 0
  ? Math.round(issues.reduce((s, i) => s + (now - new Date(i.created_at)) / DAY, 0) / issues.length)
  : 0;

// ── CI health ────────────────────────────────────────────────────
const recentRuns    = ciRuns.slice(0, 10);
const successRuns   = recentRuns.filter(r => r.conclusion === 'success').length;
const failedRuns    = recentRuns.filter(r => r.conclusion === 'failure').length;
const ciPassRate    = recentRuns.length > 0 ? Math.round((successRuns / recentRuns.length) * 100) : 100;
const lastCIStatus  = ciRuns[0]?.conclusion || 'unknown';
const lastCIEmoji   = lastCIStatus === 'success' ? '✅' : lastCIStatus === 'failure' ? '❌' : '⚪';

// ── Commit velocity ───────────────────────────────────────────────
const last7Days  = commitList.filter(c => (now - new Date(c.commit?.author?.date)) < 7  * DAY).length;
const last30Days = commitList.filter(c => (now - new Date(c.commit?.author?.date)) < 30 * DAY).length;
const commitAuthors = [...new Set(commitList.map(c => c.commit?.author?.name).filter(Boolean))];
const busFactor = commitAuthors.length;

// ── Health score algorithm ────────────────────────────────────────
// Max 100 points, deduct for problems
let score = 100;
let penalties = [];

// CI pass rate (max -30)
if (ciPassRate < 100) { const pen = Math.round((100 - ciPassRate) * 0.3); score -= pen; penalties.push(`CI pass rate ${ciPassRate}% (-${pen})`); }

// Stale PRs (max -20)
if (ancientPRs.length > 0) { const pen = Math.min(ancientPRs.length * 5, 20); score -= pen; penalties.push(`${ancientPRs.length} PR(s) >30 days old (-${pen})`); }
else if (stalePRs.length > 0) { const pen = Math.min(stalePRs.length * 2, 10); score -= pen; penalties.push(`${stalePRs.length} stale PR(s) (-${pen})`); }

// Unanswered issues (max -15)
if (unansweredIssues.length > 5) { const pen = Math.min(Math.round(unansweredIssues.length * 1.5), 15); score -= pen; penalties.push(`${unansweredIssues.length} unanswered issues (-${pen})`); }

// Bus factor (max -15)
if (busFactor === 1) { score -= 15; penalties.push('Bus factor: 1 — only 1 contributor (-15)'); }
else if (busFactor === 2) { score -= 7; penalties.push('Bus factor: 2 (-7)'); }

// Low commit velocity (max -10)
if (last7Days === 0) { score -= 10; penalties.push('No commits in last 7 days (-10)'); }
else if (last7Days < 3) { score -= 5; penalties.push(`Only ${last7Days} commit(s) this week (-5)`); }

// High open issue count (max -10)
if (issues.length > 50) { score -= 10; penalties.push(`${issues.length} open issues (-10)`); }
else if (issues.length > 20) { score -= 5; penalties.push(`${issues.length} open issues (-5)`); }

score = Math.max(0, score);
const grade = score >= 90 ? 'A' : score >= 75 ? 'B' : score >= 60 ? 'C' : score >= 40 ? 'D' : 'F';
const gradeEmoji = score >= 90 ? '🟢' : score >= 75 ? '🔵' : score >= 60 ? '🟡' : score >= 40 ? '🟠' : '🔴';

const weekLabel = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

// ── Recommendations ───────────────────────────────────────────────
const recs = [];
if (ancientPRs.length > 0) recs.push(`Review or close ${ancientPRs.length} PR(s) open >30 days`);
if (unansweredIssues.length > 3) recs.push(`Respond to ${unansweredIssues.length} issues with no comments`);
if (ciPassRate < 80) recs.push(`CI pass rate is ${ciPassRate}% — fix failing workflows`);
if (busFactor <= 2) recs.push('Onboard more contributors to reduce bus factor risk');
if (last7Days === 0) recs.push('No commits this week — is the project stalled?');

const discordReport = [
  `## ${gradeEmoji} Repo Health Report — Week of ${weekLabel}`,
  `**Score: ${score}/100 (Grade: ${grade})**`,
  '',
  '**📊 Stats**',
  `• Open PRs: ${prList.length} (${stalePRs.length} stale, ${ancientPRs.length} ancient)`,
  `• Open Issues: ${issues.length} (${unansweredIssues.length} unanswered, ${staleIssues.length} stale)`,
  `• CI Pass Rate: ${ciPassRate}% ${lastCIEmoji} (last 10 runs)`,
  `• Commits this week: ${last7Days} | this month: ${last30Days}`,
  `• Active contributors (30d): ${busFactor}`,
  '',
  recs.length > 0 ? `**⚠️ Recommendations**\n${recs.map(r => `• ${r}`).join('\n')}` : '**✅ No critical issues found!**'
].join('\n');

return [{
  json: {
    week_label: weekLabel,
    score, grade, grade_emoji: gradeEmoji,
    open_prs: prList.length,
    stale_prs: stalePRs.length,
    ancient_prs: ancientPRs.length,
    avg_pr_age: avgPRAgeDays,
    open_issues: issues.length,
    stale_issues: staleIssues.length,
    unanswered_issues: unansweredIssues.length,
    avg_issue_age: avgIssueAgeDays,
    ci_pass_rate: ciPassRate,
    ci_failed_recent: failedRuns,
    last_ci_status: lastCIStatus,
    commits_7d: last7Days,
    commits_30d: last30Days,
    bus_factor: busFactor,
    contributors: commitAuthors.join(', '),
    stars: repoInfo.stargazers_count || 0,
    forks: repoInfo.forks_count || 0,
    penalties: penalties.join('; ') || 'none',
    recommendations: recs.join(' | ') || 'None',
    discord_report: discordReport
  }
}];

